Set-StrictMode -Version 2.0
function Invoke-GodModeWslBridgeProbe { param([string]$Project='.') $r=Initialize-GodModeStructure $Project; $cmd=Get-Command wsl -ErrorAction SilentlyContinue|select -First 1; $out=''; $exit=$null; if($cmd){ try{$rr=Invoke-GodModeNativeCommand $cmd.Source @('-l','-v') (Resolve-GodModeProjectPath $Project) 8; $out=$rr.stdout+$rr.stderr; $exit=$rr.exit_code}catch{$out=$_.Exception.Message;$exit=-9} }; $h=@{schema_version=1;generated_at=Get-GodModeIso;wsl_exe_available=[bool]$cmd;wsl2_installed='unknown';default_distro='unknown';wsl_version_output=$out;repo_accessible_from_wsl='not_probed';path_translation_possible='unknown';repo_filesystem='windows';current_codex_agent_mode='windows_or_unknown';wsl_command_probe_exit_code=$exit;git_inside_wsl='not_probed';node_inside_wsl='not_probed';python_inside_wsl='not_probed';degraded_reasons=if($cmd){@()}else{@('wsl_not_available')};blockers=@()}; Write-GodModeJsonAtomic (Join-GodModePath $r 'state/wsl-health.json') $h|Out-Null; $h }
